bool SimplifyCFGOpt::simplifySwitchOnCmpIntrinsic(SwitchInst *SI,
                                                  IntrinsicInst *II,
                                                  IRBuilder<> &Builder) {
  // Try to optimize:
  //   %res = call i8 @llvm.ucmp(i32 %a, i32 %b)
  //   switch i8 %res, label %default [
  //     i8 -1, label %less
  //     i8  0, label %equal
  //     i8  1, label %greater
  //   ]
  // Note: either %less and %equal share a block, %equal and %greater share a block,
  // or %less and %greater share a block. We only optimize 2-destination switches.

  if (II->getIntrinsicID() != Intrinsic::ucmp &&
      II->getIntrinsicID() != Intrinsic::scmp)
    return false;

  // We are only handling the case where the switch cases completely cover the
  // possible values (-1, 0, 1), and there are only two unique destination blocks.
  BasicBlock *DefaultDest = SI->getDefaultDest();

  // ucmp/scmp always return -1, 0, 1. If any of those are not in cases, they go to default.
  BasicBlock *LessDest = DefaultDest;
  BasicBlock *EqualDest = DefaultDest;
  BasicBlock *GreaterDest = DefaultDest;

  for (auto Case : SI->cases()) {
    int64_t V = Case.getCaseValue()->getSExtValue();
    if (V == -1) LessDest = Case.getCaseSuccessor();
    else if (V == 0) EqualDest = Case.getCaseSuccessor();
    else if (V == 1) GreaterDest = Case.getCaseSuccessor();
    else return false; // Unexpected case value
  }

  // Find two distinct blocks if there are exactly 2 unique destinations among less, equal, greater
  BasicBlock *Dest1 = LessDest;
  BasicBlock *Dest2 = nullptr;
  if (EqualDest != Dest1) Dest2 = EqualDest;
  if (GreaterDest != Dest1 && GreaterDest != Dest2) {
    if (!Dest2) Dest2 = GreaterDest;
    else return false; // 3 unique destinations, we need at most 2
  }

  if (!Dest2) return false; // 1 unique destination, let other passes handle it

  // Determine the icmp predicate
  ICmpInst::Predicate Pred;
  bool IsSigned = II->getIntrinsicID() == Intrinsic::scmp;

  if (LessDest == EqualDest) {
    // (-1, 0) vs (1) -> <= vs >
    Pred = IsSigned ? ICmpInst::ICMP_SLE : ICmpInst::ICMP_ULE;
  } else if (EqualDest == GreaterDest) {
    // (0, 1) vs (-1) -> >= vs <
    Pred = IsSigned ? ICmpInst::ICMP_SGE : ICmpInst::ICMP_UGE;
  } else if (LessDest == GreaterDest) {
    // (-1, 1) vs (0) -> != vs ==
    Pred = ICmpInst::ICMP_NE;
  } else {
    return false;
  }

  Value *LHS = II->getArgOperand(0);
  Value *RHS = II->getArgOperand(1);
  Value *Cmp = Builder.CreateICmp(Pred, LHS, RHS);

  // The true branch corresponds to Dest1. Dest2 is the false branch.
  // Wait, if Less == Equal, then LessDest is the true branch for <=.
  BasicBlock *TrueDest = LessDest == EqualDest ? LessDest : (EqualDest == GreaterDest ? EqualDest : LessDest);
  BasicBlock *FalseDest = TrueDest == Dest1 ? Dest2 : Dest1;

  // Wait, if Less == Greater, TrueDest is LessDest for !=, which is correct.
  // Let's refine TrueDest / FalseDest.
  if (LessDest == EqualDest) { TrueDest = LessDest; FalseDest = GreaterDest; }
  else if (EqualDest == GreaterDest) { TrueDest = EqualDest; FalseDest = LessDest; }
  else if (LessDest == GreaterDest) { TrueDest = LessDest; FalseDest = EqualDest; }

  // Need weights.
  uint32_t TrueWeight = 0, FalseWeight = 0;
  // Let's keep it simple and omit weights for now, or just use simplifyTerminatorOnSelect
  return simplifyTerminatorOnSelect(SI, Cmp, TrueDest, FalseDest, TrueWeight, FalseWeight);
}

